(function(){"use strict";var SHARED_KEY="wgp_sfx_muted_v1";var LEGACY_HOTNOT_KEY="wgp_hotnot_muted_v1";var ctx=null;var muted=false;var listeners=[];function loadInitial(){try{var v=localStorage.getItem(SHARED_KEY);if(v==="1")return true;if(v==="0")return false;var legacy=localStorage.getItem(LEGACY_HOTNOT_KEY);if(legacy==="1"||legacy==="0"){var migrated=legacy==="1";localStorage.setItem(SHARED_KEY,legacy);return migrated}}catch(e){}try{if(window.matchMedia&&window.matchMedia("(prefers-reduced-motion: reduce)").matches){return true}}catch(e){}return false}muted=loadInitial();function persist(){try{localStorage.setItem(SHARED_KEY,muted?"1":"0");localStorage.setItem(LEGACY_HOTNOT_KEY,muted?"1":"0")}catch(e){}}function fire(){for(var i=0;i<listeners.length;i++){try{listeners[i](muted)}catch(e){}}}function setMuted(v){var next=!!v;if(next===muted)return;muted=next;persist();fire()}function ensureCtx(){if(ctx)return ctx;try{var AC=window.AudioContext||window.webkitAudioContext;if(!AC)return null;ctx=new AC}catch(e){return null}return ctx}function tone(opts){if(muted)return;var c=ensureCtx();if(!c)return;if(c.state==="suspended"){try{c.resume()}catch(e){}}var delay=(opts.delay||0)/1e3;var startAt=c.currentTime+delay;var dur=opts.dur||.12;var osc=c.createOscillator();var gain=c.createGain();osc.type=opts.type||"sine";if(opts.freqFrom!==void 0&&opts.freqTo!==void 0){osc.frequency.setValueAtTime(opts.freqFrom,startAt);osc.frequency.exponentialRampToValueAtTime(Math.max(20,opts.freqTo),startAt+dur)}else{osc.frequency.setValueAtTime(opts.freq||440,startAt)}var peak=opts.vol!==void 0?opts.vol:.15;gain.gain.setValueAtTime(0,startAt);gain.gain.linearRampToValueAtTime(peak,startAt+.008);gain.gain.exponentialRampToValueAtTime(1e-4,startAt+dur);osc.connect(gain);gain.connect(c.destination);osc.start(startAt);osc.stop(startAt+dur+.05)}window.wgpAudio={tone,isMuted:function(){return muted},setMuted,toggleMuted:function(){setMuted(!muted)},onMuteChange:function(fn){if(typeof fn==="function")listeners.push(fn)}}})();
